import{_ as d,o as r,c as o,a2 as a}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"AI 应用层：应用赛道","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"AI/应用层/AI应用赛道.md","filePath":"AI/应用层/AI应用赛道.md","lastUpdated":1782226922000}'),n={name:"AI/应用层/AI应用赛道.md"};function e(s,t,i,l,h,g){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="ai-应用层-应用赛道" tabindex="-1">AI 应用层：应用赛道 <a class="header-anchor" href="#ai-应用层-应用赛道" aria-label="Permalink to &quot;AI 应用层：应用赛道&quot;">​</a></h1><p><strong>成熟度：</strong> 爆发初期，各垂直赛道快速渗透 <strong>PE/VC 重心：</strong> AI Agent、AI+编程、AI+能源、AI+营销</p><hr><h2 id="一、各垂直赛道分析" tabindex="-1">一、各垂直赛道分析 <a class="header-anchor" href="#一、各垂直赛道分析" aria-label="Permalink to &quot;一、各垂直赛道分析&quot;">​</a></h2><h3 id="_1-1-ai-编程-devtools" tabindex="-1">1.1 AI+编程/DevTools <a class="header-anchor" href="#_1-1-ai-编程-devtools" aria-label="Permalink to &quot;1.1 AI+编程/DevTools&quot;">​</a></h3><p><strong>市场规模：</strong> 2026年全球~100亿USD，CAGR &gt;50% <strong>PMF已验证，海外收入模式成熟</strong></p><table tabindex="0"><thead><tr><th>产品</th><th>方向</th><th>商业模式</th><th>估值</th></tr></thead><tbody><tr><td><strong>Cursor</strong></td><td>AI IDE</td><td>$20/月订阅</td><td>~100亿+USD</td></tr><tr><td><strong>GitHub Copilot</strong></td><td>AI 编程助手</td><td>$10/月</td><td>微软旗下</td></tr><tr><td><strong>Devin (Cognition)</strong></td><td>AI 软件工程师</td><td>团队版订阅</td><td>~20亿+USD</td></tr><tr><td><strong>Windsurf (Codeium)</strong></td><td>AI IDE</td><td>$15/月</td><td>~30亿+USD</td></tr><tr><td><strong>通义灵码</strong></td><td>阿里AI编程</td><td>免费/企业版</td><td>阿里内部</td></tr><tr><td><strong>Baichuan 代码助手</strong></td><td>百川代码</td><td>企业服务</td><td>—</td></tr></tbody></table><p><strong>中国机会：</strong></p><ul><li>中国开发者~1000万，AI编程渗透率&lt;10%</li><li>国产替代：代码补全→代码审查→自动修复→AI程序员</li><li>关注有 IDE/编辑器生态基础的公司</li></ul><p><strong>PE/VC 标的方向：</strong></p><ul><li>AI 代码审查 (Code Review)</li><li>AI 测试生成 (Test Generation)</li><li>AI DevOps 自动化</li><li>垂直语言（如嵌入式C++/Rust）编程助手</li></ul><hr><h3 id="_1-2-ai-营销-数字人" tabindex="-1">1.2 AI+营销/数字人 <a class="header-anchor" href="#_1-2-ai-营销-数字人" aria-label="Permalink to &quot;1.2 AI+营销/数字人&quot;">​</a></h3><p><strong>市场规模：</strong> 2026年全球~200亿USD</p><p><strong>核心场景：</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>产品形态</th><th>成熟度</th></tr></thead><tbody><tr><td>短视频/直播数字人</td><td>实拍级数字人分身</td><td>已商用</td></tr><tr><td>AI 文案生成</td><td>广告文案/小红书/公众号</td><td>成熟</td></tr><tr><td>AI 视频广告</td><td>文生视频+数字人口播</td><td>快速成熟</td></tr><tr><td>AI 客服/营销</td><td>外呼+社群运营</td><td>较早商用</td></tr><tr><td>AI 设计</td><td>Logo/海报/产品图</td><td>成熟</td></tr></tbody></table><p><strong>中国代表公司：</strong></p><table tabindex="0"><thead><tr><th>公司</th><th>方向</th><th>阶段</th><th>备注</th></tr></thead><tbody><tr><td><strong>商汤如影</strong></td><td>数字人生成</td><td>上市集团</td><td>—</td></tr><tr><td><strong>硅基智能</strong></td><td>数字人直播/客服</td><td>C轮</td><td>南京，AIGC数字人</td></tr><tr><td><strong>出门问问</strong></td><td>AI 语音+内容生成</td><td>已上市</td><td>—</td></tr><tr><td><strong>诗云科技 (HeyGen)</strong></td><td>AI 视频生成(数字人)</td><td>B轮</td><td>深圳出海，海外营收</td></tr><tr><td><strong>右脑科技</strong></td><td>AI 视频生成</td><td>A轮</td><td>—</td></tr><tr><td><strong>特赞</strong></td><td>AI 内容管理/生成</td><td>D轮</td><td>企业内容SaaS</td></tr><tr><td><strong>极睿科技</strong></td><td>AI 电商内容</td><td>B轮</td><td>—</td></tr><tr><td><strong>句子互动</strong></td><td>AI 营销对话</td><td>B轮</td><td>私域运营</td></tr></tbody></table><hr><h3 id="_1-3-ai-医疗" tabindex="-1">1.3 AI+医疗 <a class="header-anchor" href="#_1-3-ai-医疗" aria-label="Permalink to &quot;1.3 AI+医疗&quot;">​</a></h3><p><strong>市场规模：</strong> 2026年全球~100亿USD（含药物研发） <strong>监管严格，落地较慢但壁垒高</strong></p><table tabindex="0"><thead><tr><th>方向</th><th>成熟度</th><th>壁垒</th><th>PE/VC 机会</th></tr></thead><tbody><tr><td>医学影像AI</td><td>成熟（已拿证）</td><td>审批+医院渠道</td><td>⭐⭐</td></tr><tr><td>AI 辅助诊断</td><td>中（部分已获批）</td><td>临床验证</td><td>⭐⭐⭐</td></tr><tr><td>药物研发AI</td><td>早期</td><td>数据+生物验证</td><td>⭐⭐⭐⭐</td></tr><tr><td>病历AI/NLP</td><td>中</td><td>医院IT</td><td>⭐⭐⭐</td></tr><tr><td>健康管理AI</td><td>早期</td><td>用户触达</td><td>⭐⭐</td></tr></tbody></table><p><strong>代表公司：</strong></p><ul><li><strong>晶泰科技</strong> (AI药物研发，已上市)</li><li><strong>英矽智能</strong> (AI药物研发，已上市)</li><li><strong>推想科技</strong> (AI影像，D轮)</li><li><strong>科亚医疗</strong> (AI影像，D轮)</li><li><strong>数坤科技</strong> (AI影像，D轮)</li><li><strong>深睿医疗</strong> (AI影像+决策，D轮)</li></ul><hr><h3 id="_1-4-ai-金融" tabindex="-1">1.4 AI+金融 <a class="header-anchor" href="#_1-4-ai-金融" aria-label="Permalink to &quot;1.4 AI+金融&quot;">​</a></h3><p><strong>市场规模：</strong> 2026年中国~100亿RMB <strong>金融行业付费意愿强</strong></p><table tabindex="0"><thead><tr><th>方向</th><th>说明</th><th>一级机会</th></tr></thead><tbody><tr><td>智能投研</td><td>信息聚合→数据分析→报告生成</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>智能风控</td><td>信贷/欺诈/合规</td><td>⭐⭐（已较成熟）</td></tr><tr><td>AI 量化</td><td>因子挖掘+交易执行</td><td>⭐⭐</td></tr><tr><td>AI 客服/投顾</td><td>理财助手/投教</td><td>⭐⭐⭐</td></tr><tr><td>合同/文档审核</td><td>金融合同条款审查</td><td>⭐⭐⭐</td></tr></tbody></table><p><strong>代表公司：</strong></p><ul><li><strong>文因互联</strong> (金融NLP+知识图谱，B轮)</li><li><strong>庖丁科技</strong> (金融文档AI，B轮)</li><li><strong>香侬科技</strong> (金融AI)</li><li><strong>爱简金融</strong> (智能投研)</li><li><strong>慧度资产</strong> (AI+FOF投资)</li></ul><hr><h3 id="_1-5-ai-教育" tabindex="-1">1.5 AI+教育 <a class="header-anchor" href="#_1-5-ai-教育" aria-label="Permalink to &quot;1.5 AI+教育&quot;">​</a></h3><p><strong>市场规模：</strong> 2026年全球~80亿USD</p><table tabindex="0"><thead><tr><th>方向</th><th>说明</th><th>成熟度</th></tr></thead><tbody><tr><td>AI Tutor</td><td>个性化辅导</td><td>快速发展</td></tr><tr><td>AI 教育内容</td><td>课件/试题/教案生成</td><td>初期</td></tr><tr><td>AI 口语/语言学习</td><td>对话练习</td><td>已成熟(多邻国)</td></tr><tr><td>AI 自适应测评</td><td>个性化出题+评估</td><td>发展中</td></tr></tbody></table><p><strong>代表公司：</strong></p><ul><li><strong>松鼠AI</strong> (自适应教育，上市)</li><li><strong>学而思AI</strong> (好未来，AI Tutor)</li><li><strong>网易有道AI</strong> (翻译+口语)</li><li><strong>蝴蝶AI</strong> (AI 1对1辅导)</li></ul><hr><h3 id="_1-6-ai-法律" tabindex="-1">1.6 AI+法律 <a class="header-anchor" href="#_1-6-ai-法律" aria-label="Permalink to &quot;1.6 AI+法律&quot;">​</a></h3><p><strong>市场空间：</strong> 2026年中国~20亿RMB</p><table tabindex="0"><thead><tr><th>方向</th><th>机会</th></tr></thead><tbody><tr><td>合同审查</td><td>标准化条款→风险标注→修改建议</td></tr><tr><td>法规检索</td><td>法律法规+判例+解读</td></tr><tr><td>智能磋商</td><td>AI辅助谈判策略</td></tr><tr><td>诉讼预测</td><td>胜率分析+赔偿金额预测</td></tr></tbody></table><p><strong>代表公司：</strong></p><ul><li><strong>法天使</strong> (合同库+AI审查，A轮)</li><li><strong>幂律智能</strong> (法律AI，A轮)</li><li><strong>植德AI</strong> (律所内部工具)</li><li><strong>秘塔AI</strong> (法律搜索+写作)</li></ul><hr><h3 id="_1-7-ai-能源-重点交叉" tabindex="-1">1.7 AI+能源（重点交叉） <a class="header-anchor" href="#_1-7-ai-能源-重点交叉" aria-label="Permalink to &quot;1.7 AI+能源（重点交叉）&quot;">​</a></h3><p><strong>市场空间：</strong> 2026年中国~50亿RMB <strong>壁垒：行业数据+物理模型+AI 三者结合</strong></p><table tabindex="0"><thead><tr><th>方向</th><th>说明</th><th>PE/VC 推荐度</th></tr></thead><tbody><tr><td>AI 功率预测</td><td>风光出力+负荷预测</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>AI 智能运维</td><td>风机/光伏/储能设备预测性维护</td><td>⭐⭐⭐⭐</td></tr><tr><td>AI 电力交易</td><td>现货市场报价策略优化</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>AI 虚拟电厂</td><td>聚合资源调度优化</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td>AI 碳管理</td><td>碳排放核算+监测</td><td>⭐⭐⭐</td></tr><tr><td>AI 储能调度</td><td>SOC优化+充放电策略</td><td>⭐⭐⭐⭐</td></tr></tbody></table><p><strong>代表公司：</strong></p><ul><li><strong>瓦特智能</strong> (AI功率预测+电力交易)</li><li><strong>清大科越</strong> (电力市场+AI调度)</li><li><strong>电享科技</strong> (VPP+AI)</li><li><strong>浙达能源</strong> (能源AI平台)</li><li><strong>深度风维</strong> (风电AI运维)</li><li><strong>江行智能</strong> (边缘AI+能源)</li></ul><hr><h2 id="二、ai-agent-平台-2026-最大热点" tabindex="-1">二、AI Agent 平台（2026 最大热点） <a class="header-anchor" href="#二、ai-agent-平台-2026-最大热点" aria-label="Permalink to &quot;二、AI Agent 平台（2026 最大热点）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>说明</th><th>代表</th></tr></thead><tbody><tr><td>通用AI Agent</td><td>自主规划执行任务</td><td>Manus、AutoGPT</td></tr><tr><td>垂直AI Agent</td><td>专业领域自主工作流</td><td>Devin(编程)、法律Agent</td></tr><tr><td>Agent 平台/框架</td><td>构建Agent的开发平台</td><td>LangChain、Dify、Coze</td></tr><tr><td>Agent 托管/运行</td><td>Agent 云服务</td><td>—</td></tr></tbody></table><p><strong>关注点：</strong></p><ul><li>Agent 的&quot;可靠性&quot;壁垒——用户容忍度极低</li><li>工具调用准确率是关键瓶颈</li><li>长期看 Agent 平台 &gt; 单个 Agent 产品</li></ul><hr><h2 id="三、投资逻辑总结" tabindex="-1">三、投资逻辑总结 <a class="header-anchor" href="#三、投资逻辑总结" aria-label="Permalink to &quot;三、投资逻辑总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>子赛道</th><th>推荐度</th><th>时机</th><th>壁垒</th></tr></thead><tbody><tr><td>AI+编程（中国）</td><td>⭐⭐⭐⭐⭐</td><td>窗口期</td><td>编辑器生态+开发者社区</td></tr><tr><td>AI+能源（交叉）</td><td>⭐⭐⭐⭐⭐</td><td>早期布局</td><td>行业数据+物理模型</td></tr><tr><td>AI+金融（投研）</td><td>⭐⭐⭐⭐</td><td>成长期</td><td>金融数据+市场经验</td></tr><tr><td>AI Agent 平台</td><td>⭐⭐⭐⭐⭐</td><td>爆发前夜</td><td>工具链+生态</td></tr><tr><td>AI+法律</td><td>⭐⭐⭐</td><td>早期</td><td>法律知识库</td></tr><tr><td>AI+营销/数字人</td><td>⭐⭐⭐</td><td>竞争激烈</td><td>渠道+客户</td></tr><tr><td>AI+医疗（药物研发）</td><td>⭐⭐⭐</td><td>长周期</td><td>生物学验证</td></tr></tbody></table><hr><h2 id="四、交叉链接" tabindex="-1">四、交叉链接 <a class="header-anchor" href="#四、交叉链接" aria-label="Permalink to &quot;四、交叉链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关联赛道</th><th>链接</th><th>说明</th></tr></thead><tbody><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/赛道总览">赛道总览</a></td><td>AI+电力交易、AI+VPP 调度</td></tr><tr><td><strong>算电协同</strong></td><td><a href="./../算电协同/投资逻辑">投资逻辑</a></td><td>AI 电力交易平台是 P0 布局方向</td></tr><tr><td><strong>储能</strong></td><td><a href="./../../电力新能源/储能/产业链">产业链</a></td><td>AI+储能调度</td></tr><tr><td><strong>智能电网/VPP</strong></td><td><a href="./../../电力新能源/智能电网/新兴赛道#二虚拟电厂-vpp">新兴赛道</a></td><td>AI VPP 聚合</td></tr></tbody></table>',59)])])}const b=d(n,[["render",e]]);export{I as __pageData,b as default};
